   435 |     if (I.isCommutative()) {
   436 |       if (auto Pair = matchSymmetricPair(I.getOperand(0), I.getOperand(1))) {
   437 |         replaceOperand(I, 0, Pair->first);
   438 |         replaceOperand(I, 1, Pair->second);
   439 |         Changed = true;
   440 |       }
   441 |     }
